ee:variables.ee:set-variable:
%dw 2.0
output application/java
var modPayload = payload -- ['CompanyId']
---
{
	query: (modPayload filterObject ((value, key) -> !isEmpty(value)) pluck ((value, key) -> 
            if ( upper(key) == "CENTRALPHONENUMBER" ) 
            	"CentralPhoneNumber eq '" ++ (value as String) ++ "'"
          /**  else if ( upper(key) == "EMAILADDRESS" ) 
            	"substringof('" ++ value ++ "',EmailAddress)"  */
            else if ( upper(key) == "PHYSADDRESS1" ) 
            	"startswith(PhysAddress1,'" ++ (value as String) ++ "')"
            else
                    "substringof('" ++ (value as String) ++ "', " ++ key ++ ")"
        ) filter ((item) -> item != "") joinBy " and ")
}

%dw 2.0
output application/java
---
{
	query: "CustomerId eq '" ++ payload
}

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
if (isEmpty(vars.customersArray))
    {
        status: "Success",
        results: [],
        correlationId: vars.correlationId,
        message: "The Company ID provided does not match the Company ID associated with the customer record."
    }
else
