ee:variables.ee:set-variable:
%dw 2.0
output application/java
import dwl::specialcharutils as specialcharutil
//import dwl::updateSync as util
---
{
    query: (
        payload 
        filterObject ((value, key) -> !isEmpty(value))
        pluck ((value, key) -> 
            if (!isEmpty(payload.CustomerName) or !isEmpty(payload.CompanyId))
                if (upper(key) == "COMPANYID")
                    "CompanyId eq '" ++ (value as String) ++ "'"
                else


                	   "startswith(CustomerName,'" ++ (specialcharutil::handleSpecialCharForP21(value) as String) ++ "')"
                   /** "substringof('" ++(util::customUrlEncode(value) as String) ++ "', " ++ key ++ ")" */
           /** else if (!isEmpty(payload.FirstName) or !isEmpty(payload.LastName))
            	"startswith(" ++ key ++",'" ++ (value as String) ++ "')"  */
            else
                if (upper(key) == "CENTRALPHONENUMBER")
                    "CentralPhoneNumber eq '" ++ (value as String) ++ "'"
                else if (upper(key) == "CUSTOMERID")
                    "CorpAddressId eq '" ++ (value as String) ++ "'"
                else if (upper(key) == "PHYSADDRESS1")
                    "startswith(PhysAddress1,'" ++ (value as String) ++ "')"
                else
                    "substringof('" ++ (value as String) ++ "', " ++ key ++ ")"
        )
        filter ((item) -> item != "")
        joinBy " and "
    )
}

