ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
{
    filter: (
        payload 
        filterObject ((value, key) -> !isEmpty(value))
        pluck ((value, key) -> 
            if (key as String == "CompanyName")
				"company_name eq '" ++ (value as String) ++ "'"
            else if (key as String == "CompanyId")
	            "company_id eq '" ++ (value as String) ++ "'"
	        else if (key as String == "CentralPhoneNumber")
	            "direct_phone eq '" ++ (value as String) ++ "'"
	        else if (key as String  == "PhysAddress1")
	            "phys_address1 eq '" ++ (value as String) ++ "'"
	        else if (key as String == "EmailAddress")
	            "email_address eq '" ++ (value as String) ++ "'"
	        else if (key as String == "CustomerId")
	            "customer_id eq '" ++ (value as String) ++ "'"
	        else if (key as String == "FirstName")
	            "first_name eq '" ++ (value as String) ++ "'"
	        else if (key as String == "LastName")
	            "last_name eq '" ++ (value as String) ++ "'"
	        else
	            (key as String) ++ " eq '" ++ (value as String) ++ "'"
        )
        filter ((item) -> item != "")
        joinBy " and "
    )
}

ee:message.ee:set-payload:
%dw 2.0
output application/json
var customer = payload
---
{
    Name: "Customer",
    Description: null,
    UseCodeValues: false,
    IgnoreDisabled: true,
    Transactions: [
        {
            Status: "New",
            DataElements: [
                {
                    Name: "TABPAGE_1.tp_1_dw_1",
                    BusinessObjectName: null,
                    Type: "Form",
                    Keys: ["company_id", "customer_id"],
                    Rows: [
                        {
                            Edits: [
                                {
                                    Name: "company_id",
                                    Value: customer.CompanyId default "",
                                    IgnoreIfEmpty: true
                                },
                                {
                                    Name: "customer_id",
                                    Value: customer.CustomerId default "",
                                    IgnoreIfEmpty: true
                                }
                            ],
                            RelativeDateEdits: []
                        }
                    ]
                },
                {
                    Name: "LINKS.links",
                    BusinessObjectName: null,
                    Type: "List",
                    Keys: ["contact_id", "contact_type_cd", "contact_link_id"],
                    Rows: 

                        (customer.CustomerContacts.OEContactsCustomer default [])
                        map (contact) -> {
                            Edits: [
                                {
                                    Name: "contact_id",
                                    Value: contact.ContactId default "",
                                    IgnoreIfEmpty: true
                                },
                                {
                                    Name: "contact_type_cd",
                                    Value: "Customer",
                                    IgnoreIfEmpty: true
                                },
                                {
                                    Name: "contact_link_id",
                                    Value: contact.CustomerId default "",
                                    IgnoreIfEmpty: true
                                }
                            ],
                            RelativeDateEdits: []
                        }
                }
            ],
            Documents: null
        }
    ]
}
